for (const r of rows) {
  const nombre_intermediario = (r.frm_gen_nombre_intermediario || "")
    .trim();

  if (!nombre_intermediario) continue;

  counts.set(nombre_intermediario, (counts.get(nombre_intermediario) || 0) + 1);
}

const duplicates = [];
